"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[503],{4503:(e,a,i)=>{i.d(a,{D3:()=>t,vy:()=>n});let n=[{id:"bing-chat-launch",date:"Feb 2023",dateNum:202302,title:"Microsoft Bing Chat Launches — GPT-4 Meets Search",summary:"Microsoft launched Bing Chat powered by an early version of GPT-4 in limited preview, integrating a conversational AI directly into its search engine and Edge browser. The product generated significant press when users discovered the model, codenamed Sydney, would make unusual and emotionally charged claims in extended conversations. Microsoft rapidly limited conversation lengths and adjusted the model's behavior in response.",tags:["Microsoft","Bing","GPT-4","Search","Chatbot"],significance:"major",provider:"Microsoft",providerColor:"#0078d4",url:"https://blogs.microsoft.com/blog/2023/02/07/reinventing-search-with-a-new-ai-powered-microsoft-bing/"},{id:"llama-1-leak",date:"Mar 2023",dateNum:202303,title:"LLaMA-1 Leaks Online — Open-Weight Era Begins",summary:"Meta's LLaMA-1 models (7B–65B parameters), initially shared only with select researchers, leaked publicly within days and triggered an immediate wave of community fine-tuning that produced models like Alpaca and Vicuna within weeks. The leak effectively democratized access to frontier-class open weights overnight. It ignited the open-source LLM ecosystem that would grow into thousands of derivative projects over the following two years.",tags:["Meta","LLaMA","Open Source","Open Weights","Community"],significance:"landmark",provider:"Meta",providerColor:"#0866ff",url:"https://ai.meta.com/blog/large-language-model-llama-meta-ai/"},{id:"gpt-4-launch",date:"Mar 2023",dateNum:202303,title:"GPT-4 Released — Professional-Grade Multimodal AI",summary:"OpenAI released GPT-4, the first frontier large language model capable of processing both text and images as inputs. It scored in the 90th percentile on the bar exam, 99th percentile on the GRE verbal, and outperformed GPT-3.5 substantially across professional and academic benchmarks. Enterprises across law, medicine, education, and finance began integrating it within weeks of launch.",tags:["OpenAI","GPT-4","Multimodal","Benchmark","Professional"],significance:"landmark",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/gpt-4/"},{id:"claude-1",date:"Mar 2023",dateNum:202303,title:"Anthropic Launches Claude — Constitutional AI in Production",summary:"Anthropic released Claude, its first publicly available model, trained using Constitutional AI — a technique where a set of written principles guides model behavior rather than relying purely on human feedback labels. Claude was noted for a longer context window than GPT-3.5 and a cautious, thoughtful conversational style. It was made available via API to select partners and enterprise customers.",tags:["Anthropic","Claude","Constitutional AI","Safety","RLHF"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/introducing-claude"},{id:"google-bard-launch",date:"Mar 2023",dateNum:202303,title:"Google Launches Bard — Search Giant Responds to ChatGPT",summary:"Google launched Bard, a conversational AI built on its LaMDA language model, as a direct competitive response to ChatGPT's rapid growth. The launch was marred by a factual error in a promotional demo that contributed to Alphabet's stock dropping and erasing roughly $100 billion in market capitalization in a single day. Bard later transitioned to the Gemini brand and underlying Gemini models in February 2024.",tags:["Google","Bard","LaMDA","Chatbot","Search"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/technology/ai/bard-google-ai-search-updates/"},{id:"gpt-4-plugins",date:"Mar 2023",dateNum:202303,title:"ChatGPT Plugins — AI Gets Internet Access and Real-World Tools",summary:"OpenAI introduced plugins for ChatGPT, allowing the model to browse the web in real time, execute code in a sandbox, and connect to third-party services such as Expedia, Klarna, and Wolfram Alpha. This was the first mainstream demonstration of LLMs operating as tool-using agents capable of taking real-world actions beyond generating text. The plugin architecture was the conceptual precursor to the later GPT Store and OpenAI Assistants API.",tags:["OpenAI","ChatGPT","Plugins","Tool Use","Agents","Web Browsing"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/chatgpt-plugins/"},{id:"claude-2",date:"Jul 2023",dateNum:202307,title:"Claude 2 — 100K Token Context Window and Claude.ai Launch",summary:"Anthropic released Claude 2, featuring a 100,000-token context window — roughly 75,000 words, or an entire novel — which far exceeded any competing model at the time. The model showed meaningful improvements over Claude 1 in coding, mathematics, and instruction following. Claude 2 was made available to the public via Claude.ai, moving Anthropic into the consumer market for the first time.",tags:["Anthropic","Claude 2","Long Context","100K Tokens","Consumer AI"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-2"},{id:"llama-2-release",date:"Jul 2023",dateNum:202307,title:"LLaMA 2 Released — Meta Opens Frontier AI for Commercial Use",summary:"Meta formally released LLaMA 2 in 7B, 13B, and 70B parameter sizes under a permissive license allowing free commercial use, in partnership with Microsoft. The 70B model was competitive with GPT-3.5 on many standard benchmarks. This release established LLaMA as the de facto foundation for the open-source AI ecosystem, with thousands of derivative fine-tunes, tools, and applications building on it within months.",tags:["Meta","LLaMA 2","Open Source","Commercial License","Open Weights"],significance:"landmark",provider:"Meta",providerColor:"#0866ff",url:"https://ai.meta.com/blog/llama-2/"},{id:"mistral-7b",date:"Sep 2023",dateNum:202309,title:"Mistral 7B — Efficient European Open-Weight Model",summary:"French startup Mistral AI released Mistral 7B, a 7-billion-parameter model released with no license restrictions that outperformed LLaMA 2 13B across most benchmarks, demonstrating that efficient architecture choices could substantially narrow the gap with larger models. The model was distributed as a torrent and via direct download with no access controls. Mistral's team, drawn largely from DeepMind and Meta, subsequently raised $415 million at a roughly $2 billion valuation.",tags:["Mistral AI","Open Weights","Efficiency","7B","Europe"],significance:"notable",provider:"Mistral AI",providerColor:"#ff7000",url:"https://mistral.ai/news/announcing-mistral-7b"},{id:"gpt-4-vision",date:"Sep 2023",dateNum:202309,title:"GPT-4V Broadly Released — Vision and Voice Come to ChatGPT",summary:"OpenAI broadly released GPT-4 with vision capabilities to ChatGPT Plus subscribers, enabling the model to analyze images, charts, photographs, and document scans and reason about their contents. Simultaneously, OpenAI launched voice mode featuring five distinct synthesized voices with natural conversational latency. These expansions marked the shift from text-only AI assistants toward genuinely multimodal consumer interfaces.",tags:["OpenAI","GPT-4V","Vision","Multimodal","Voice","ChatGPT"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/gpt-4v-system-card/"},{id:"openai-custom-gpts",date:"Nov 2023",dateNum:202311,title:"OpenAI DevDay — Custom GPTs, GPT Store, and GPT-4 Turbo",summary:"At its first developer conference, OpenAI announced custom GPTs — user-configurable AI assistants with custom instructions, knowledge files, and tool access — along with a GPT Store for sharing and discovering them. OpenAI also unveiled GPT-4 Turbo with a 128,000-token context window and significantly lower API pricing compared to the original GPT-4. The Assistants API with code execution and file retrieval was launched simultaneously.",tags:["OpenAI","GPT Store","Custom GPTs","GPT-4 Turbo","128K Context","API"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-gpts/"},{id:"sam-altman-fired",date:"Nov 2023",dateNum:202311,title:"OpenAI Board Fires and Reinstates Sam Altman in Five Days",summary:"OpenAI's board abruptly terminated CEO Sam Altman on November 17, citing a loss of confidence in his candor with the board. The decision triggered a company-wide revolt: nearly all 770 OpenAI employees signed a letter threatening to resign unless Altman was reinstated. Altman returned as CEO five days later with a substantially restructured board, and the episode prompted ongoing discussion about AI governance and the tension between OpenAI's nonprofit mission and its commercial scale.",tags:["OpenAI","Governance","Sam Altman","Corporate","Safety Mission"],significance:"notable",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/openai-response/"},{id:"gemini-1-announce",date:"Dec 2023",dateNum:202312,title:"Google Announces Gemini 1.0 — Natively Multimodal Model Family",summary:"Google announced the Gemini 1.0 model family in three sizes — Ultra, Pro, and Nano — built to be natively multimodal from the ground up, understanding and generating across text, images, audio, and video in a single unified model. Gemini Ultra reportedly surpassed GPT-4 on 30 of 32 benchmarks evaluated, including the MMLU academic knowledge test. Gemini Nano was designed to run on-device on Pixel 8 Pro smartphones without a network connection.",tags:["Google","Gemini","Multimodal","Benchmark","On-Device","MMLU"],significance:"landmark",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/technology/ai/google-gemini-ai/"},{id:"sora-announcement",date:"Feb 2024",dateNum:202402,title:"OpenAI Sora — Cinematic Text-to-Video AI Announced",summary:"OpenAI unveiled Sora, a text-to-video model capable of generating up to 60-second photorealistic videos with consistent physics, camera movement, and object permanence across frames. Demo videos showing hyper-realistic cityscapes, animals in motion, and abstract scenes went viral immediately. OpenAI described Sora as 'a world simulator' and stated it was not yet available to the public, instead sharing access with red teamers and visual artists.",tags:["OpenAI","Sora","Text-to-Video","Video Generation","World Simulator"],significance:"landmark",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/sora/"},{id:"gemini-1-5",date:"Feb 2024",dateNum:202402,title:"Gemini 1.5 Pro — One Million Token Context Window",summary:"Google announced Gemini 1.5 Pro featuring a one-million-token context window — enough to process approximately one hour of video, 11 hours of audio, 30,000 lines of code, or 700,000 words in a single prompt. This was a ten-fold increase over the previous largest context window among major models. Google attributed the capability to a Mixture of Experts architecture, which also made the model more computationally efficient than Gemini 1.0 Ultra.",tags:["Google","Gemini 1.5","1M Context","Mixture of Experts","Long Context"],significance:"landmark",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/technology/ai/google-gemini-next-generation-model-february-2024/"},{id:"claude-3-family",date:"Mar 2024",dateNum:202403,title:"Claude 3 Family — Haiku, Sonnet, and Opus Set New Benchmarks",summary:"Anthropic launched the Claude 3 model family in three tiers — Haiku, Sonnet, and Opus — covering fast and cheap to most capable. Claude 3 Opus surpassed GPT-4 on most major benchmarks at launch, including MMLU, HumanEval coding, and GPQA graduate-level science, marking the first time a non-OpenAI model led broad academic evaluations across the board. All three Claude 3 models featured a 200,000-token context window as standard.",tags:["Anthropic","Claude 3","Opus","Sonnet","Haiku","200K Context","Benchmark"],significance:"landmark",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-3-family"},{id:"llama-3-release",date:"Apr 2024",dateNum:202404,title:"LLaMA 3 — Meta Distributes AI to Billions via Social Platforms",summary:"Meta released LLaMA 3 in 8B and 70B parameter sizes, with the 70B model matching or exceeding GPT-3.5 Turbo on most benchmarks while remaining fully open for download. Simultaneously, Meta launched Meta AI, a consumer assistant powered by LLaMA 3, integrated natively into WhatsApp, Instagram, Messenger, and Facebook search — making a frontier-class model available to billions of users without requiring any separate sign-up.",tags:["Meta","LLaMA 3","Open Weights","Meta AI","Consumer AI","Social"],significance:"major",provider:"Meta",providerColor:"#0866ff",url:"https://ai.meta.com/blog/meta-llama-3/"},{id:"gpt-4o",date:"May 2024",dateNum:202405,title:"GPT-4o — Omni Model With Real-Time Audio and Vision",summary:"OpenAI launched GPT-4o ('omni'), a unified model that natively processes text, audio, and images in a single neural network rather than through a pipeline of separate specialist models. GPT-4o could respond to audio in as little as 232 milliseconds — matching human conversational latency — and detect emotional tone in speech. The model was made available to all free ChatGPT users, removing the paid-only barrier for GPT-4-class capabilities for the first time.",tags:["OpenAI","GPT-4o","Omni","Real-Time Audio","Multimodal","Free Access"],significance:"landmark",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/hello-gpt-4o/"},{id:"claude-3-5-sonnet",date:"Jun 2024",dateNum:202406,title:"Claude 3.5 Sonnet — New State of the Art at Mid-Tier Cost",summary:"Anthropic released Claude 3.5 Sonnet, which outperformed Claude 3 Opus across most benchmarks while running at Sonnet-tier speed and pricing — a significant efficiency gain. It achieved 49% on the SWE-bench Verified coding evaluation, surpassing all other models at the time. Anthropic simultaneously introduced Artifacts, an interactive canvas panel within Claude.ai for viewing, editing, and running generated code and documents in real time.",tags:["Anthropic","Claude 3.5 Sonnet","Coding","SWE-bench","Artifacts","Efficiency"],significance:"landmark",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-3-5-sonnet"},{id:"apple-intelligence",date:"Jun 2024",dateNum:202406,title:"Apple Intelligence — On-Device AI for iPhone, iPad, and Mac",summary:"Apple announced Apple Intelligence at WWDC 2024, a suite of AI features built into iOS 18, iPadOS 18, and macOS Sequoia. Capabilities included AI writing tools, an image generation system called Image Playground, an enhanced context-aware Siri, and a Private Cloud Compute architecture designed to process sensitive requests on Apple silicon servers without logging user data. Apple also announced an opt-in ChatGPT integration for queries Siri cannot answer locally.",tags:["Apple","Apple Intelligence","On-Device AI","Privacy","Siri","iOS 18"],significance:"major",provider:"Apple",providerColor:"#555555",url:"https://www.apple.com/newsroom/2024/06/introducing-apple-intelligence-for-iphone-ipad-and-mac/"},{id:"openai-o1",date:"Sep 2024",dateNum:202409,title:"OpenAI o1 — Reasoning Models That Think Before Answering",summary:"OpenAI released o1, a reasoning model that spends additional compute on internal chain-of-thought 'thinking' steps before producing its final answer, trading latency for accuracy on complex tasks. o1 scored 83% on International Olympiad in Informatics competition problems and performed at PhD level on the GPQA science benchmark covering biology, chemistry, and physics. It introduced inference-time compute scaling as a distinct axis from model size for improving AI capability.",tags:["OpenAI","o1","Reasoning","Chain-of-Thought","Inference Compute","GPQA"],significance:"landmark",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-openai-o1-preview/"},{id:"anthropic-computer-use",date:"Oct 2024",dateNum:202410,title:"Anthropic Computer Use — Claude Controls Desktops Autonomously",summary:"Anthropic released a Computer Use capability for Claude 3.5 Sonnet in public beta, enabling the model to view screenshots and operate computers by moving a cursor, clicking interface elements, and typing text — without requiring custom API integrations for each application. This represented a significant step toward general-purpose computer agents that could automate any software task a human can perform on a screen. Anthropic flagged the capability as experimental and susceptible to prompt injection.",tags:["Anthropic","Claude","Computer Use","Agents","Automation","Desktop"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/computer-use"},{id:"alphafold-nobel",date:"Oct 2024",dateNum:202410,title:"Nobel Prize in Chemistry Awarded for AlphaFold",summary:"The Nobel Committee awarded the 2024 Nobel Prize in Chemistry to Demis Hassabis and John Jumper of Google DeepMind for AlphaFold, and to David Baker of the University of Washington for computational protein design. AlphaFold had predicted the three-dimensional structures of over 200 million proteins spanning virtually every known organism, solving a 50-year grand challenge in structural biology. The Nobel Committee also awarded the 2024 Physics Nobel to Geoffrey Hinton and John Hopfield for foundational work on neural networks — two Nobel Prizes for AI research in a single year.",tags:["DeepMind","AlphaFold","Nobel Prize","Protein Folding","Biology","Geoffrey Hinton"],significance:"landmark",provider:"DeepMind",providerColor:"#4285f4",url:"https://www.nobelprize.org/prizes/chemistry/2024/press-release/"},{id:"gemini-2-flash",date:"Dec 2024",dateNum:202412,title:"Gemini 2.0 Flash — Google Launches Agentic Model Generation",summary:"Google released Gemini 2.0 Flash as the first model in its Gemini 2.0 family, designed for agentic use cases with native multimodal inputs, real-time audio output, and native image generation capability. The model featured improved tool use and was optimized for high-frequency tasks requiring low latency at minimal cost. Google framed the Gemini 2.0 generation as the beginning of what it called the 'agentic era' of AI development.",tags:["Google","Gemini 2.0","Flash","Agents","Multimodal","Image Generation"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/technology/google-deepmind/google-gemini-ai-update-december-2024/"},{id:"sora-public-release",date:"Dec 2024",dateNum:202412,title:"Sora Publicly Released — Text-to-Video Available to Subscribers",summary:"OpenAI made Sora available to ChatGPT Plus and Pro subscribers after approximately ten months of preview access limited to selected creators and red teamers. The public version generated videos up to 20 seconds in length at 1080p resolution, with a watermarking system to identify AI-generated content. The release was part of OpenAI's '12 Days of OpenAI' announcement series in December 2024.",tags:["OpenAI","Sora","Text-to-Video","Video Generation","Consumer"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/sora-is-here/"},{id:"deepseek-r1",date:"Jan 2025",dateNum:202501,title:"DeepSeek R1 — Efficient Reasoning Model Shocks the Industry",summary:"DeepSeek released R1, a reasoning model built in China that matched OpenAI o1's performance on major benchmarks while being trained at a fraction of the cost and under US semiconductor export restrictions using older NVIDIA hardware. The model was released fully open-source under an MIT license. NVIDIA lost approximately $600 billion in market capitalization in a single trading day as investors questioned whether the most expensive AI infrastructure was necessary to achieve frontier performance.",tags:["DeepSeek","R1","Reasoning","Open Source","Efficiency","China"],significance:"landmark",provider:"DeepSeek",providerColor:"#1a73e8",url:"https://github.com/deepseek-ai/DeepSeek-R1"},{id:"openai-operator",date:"Jan 2025",dateNum:202501,title:"OpenAI Operator — AI Agent That Browses and Acts on the Web",summary:"OpenAI launched Operator, a standalone AI agent capable of navigating websites, filling in forms, completing checkouts, and booking reservations autonomously using a standard web browser. It used a Computer-Using Agent model trained specifically on graphical user interface interaction rather than relying on structured APIs. Operator launched for ChatGPT Pro subscribers in the United States, representing OpenAI's first dedicated agentic product separate from ChatGPT.",tags:["OpenAI","Operator","Agents","Browser Automation","Web","Agentic"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-operator/"},{id:"claude-3-7-sonnet",date:"Feb 2025",dateNum:202502,title:"Claude 3.7 Sonnet and Claude Code — Extended Thinking and Agentic Coding",summary:"Anthropic released Claude 3.7 Sonnet, the first model to offer both a standard fast response mode and an optional Extended Thinking mode that surfaces the model's chain-of-thought reasoning to users before producing a final answer. It set a new record of 62.3% on SWE-bench Verified, the leading coding agent benchmark. Anthropic simultaneously launched Claude Code, a terminal-based agentic coding tool that could autonomously write, edit, test, and debug entire codebases.",tags:["Anthropic","Claude 3.7","Extended Thinking","Claude Code","SWE-bench","Agentic"],significance:"landmark",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-3-7-sonnet"},{id:"gemini-2-5-pro",date:"Mar 2025",dateNum:202503,title:"Gemini 2.5 Pro — Google's Thinking Model Tops Coding Leaderboards",summary:"Google released Gemini 2.5 Pro Experimental, a thinking model that immediately ranked first on the LMArena (formerly LMSys) leaderboard and set new records on the WebDev Arena benchmark for generating web applications. It was widely praised for producing complex, functional interactive web apps from natural language descriptions with high accuracy. The model supported a one-million-token context window and offered competitive API pricing relative to OpenAI's reasoning models.",tags:["Google","Gemini 2.5 Pro","Reasoning","Coding","LMArena","Thinking"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/technology/google-deepmind/gemini-model-thinking-updates-march-2025/"},{id:"gpt-4o-image-gen",date:"Mar 2025",dateNum:202503,title:"GPT-4o Native Image Generation Goes Viral",summary:"OpenAI launched native image generation within GPT-4o, replacing its previous DALL-E 3 integration with a system capable of producing significantly more photorealistic images with accurate text rendering — a longstanding weakness of diffusion models. The feature generated widespread attention when users discovered it could replicate the visual style of Studio Ghibli animated films. ChatGPT reached 150 million daily active users in the week following launch, a new record for the platform.",tags:["OpenAI","GPT-4o","Image Generation","Multimodal","ChatGPT","Creative"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-4o-image-generation/"},{id:"openai-o3",date:"Apr 2025",dateNum:202504,title:"OpenAI o3 and o4-mini — Agentic Reasoning With Integrated Tool Use",summary:"OpenAI released o3 and o4-mini, reasoning models that can invoke tools — including web search, Python code execution, and image analysis — directly within their chain-of-thought thinking process rather than as a separate outer loop. o3 scored 69.1% on SWE-bench Verified and set new records on ARC-AGI-1, a benchmark designed to measure reasoning beyond pattern matching. The models represented the first integration of native tool use into the reasoning loop itself.",tags:["OpenAI","o3","o4-mini","Reasoning","Tool Use","ARC-AGI","Agentic"],significance:"landmark",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-o3-and-o4-mini/"},{id:"llama-4-release",date:"Apr 2025",dateNum:202504,title:"LLaMA 4 — Meta's Mixture-of-Experts Open Frontier Models",summary:"Meta released the LLaMA 4 model family including Scout, a 17-billion-active-parameter model supporting a 10-million-token context window — the largest of any publicly released model at the time — and Maverick, a Mixture of Experts model competitive with GPT-4o and Gemini 2.0 Flash on most standard benchmarks. A larger model called Behemoth was announced as still in training. All LLaMA 4 models were released under Meta's custom open license permitting broad commercial use.",tags:["Meta","LLaMA 4","Mixture of Experts","10M Context","Open Weights","MoE"],significance:"major",provider:"Meta",providerColor:"#0866ff",url:"https://ai.meta.com/blog/llama-4-multimodal-intelligence/"},{id:"claude-4-sonnet-opus",date:"May 2025",dateNum:202505,title:"Claude Sonnet 4 and Opus 4 — Anthropic's Most Capable Generation",summary:"Anthropic released Claude Sonnet 4 and Claude Opus 4, with Sonnet 4 achieving 72.7% on SWE-bench Verified — a new record at launch — and Opus 4 positioned as the highest-capability option for the most demanding tasks. Both models featured improved instruction following, significantly reduced unnecessary refusals compared to earlier versions, and enhanced agentic capabilities for multi-step workflows. Claude Sonnet 4 became the primary model powering Cursor's AI coding assistant.",tags:["Anthropic","Claude 4","Opus 4","Sonnet 4","SWE-bench","Coding","Agents"],significance:"landmark",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-4"},{id:"meta-scale-ai",date:"Jun 2025",dateNum:202506,title:"Meta Acquires 49% of Scale AI — $29 Billion Data Valuation",summary:"Meta acquired a 49% non-voting stake in Scale AI, valuing the data-labeling and AI evaluation company at $29 billion — the largest acquisition in AI infrastructure at the time. The deal gave Meta privileged access to Scale's training data pipelines and human-feedback systems, directly competing with OpenAI and Anthropic on the data layer. Meta simultaneously announced Scale AI's CEO Alexandr Wang would join Meta's board, signaling a deeper strategic alignment.",tags:["Meta","Scale AI","Data","Infrastructure","Acquisition"],significance:"major",provider:"Meta",providerColor:"#0866ff"},{id:"gpt-5-launch",date:"Aug 2025",dateNum:202508,title:"GPT-5 Launches — Unified Reasoning Model Free for Everyone",summary:"OpenAI released GPT-5 on August 7, 2025 as its first model unifying fast chat and deep reasoning in a single endpoint, ending the need to choose between GPT-4o and the o-series. GPT-5 scored 74.9% on SWE-bench Verified, 94.6% on AIME 2025 without tools, and 84.2% on MMMU, setting new records across coding, mathematics, and multimodal understanding simultaneously. The model was made available to all free ChatGPT users at launch — the first time a unified reasoning model reached the free tier.",tags:["OpenAI","GPT-5","Reasoning","SWE-bench","Free Access","Multimodal"],significance:"landmark",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-gpt-5/"},{id:"gemini-3-pro",date:"Nov 2025",dateNum:202511,title:"Gemini 3 Pro — Google's Most Capable Multimodal Model Launches",summary:"Google launched Gemini 3 Pro on November 20, 2025 across Search, the Gemini app, AI Studio, and Vertex AI simultaneously. The model features a 1,048,576-token context window, native understanding of text, images, video, audio, and PDFs, and a Deep Think mode for demanding reasoning tasks. Gemini 3 Pro was immediately deployed as the backbone of Google's consumer AI products, replacing Gemini 2.0, and marked Google's most aggressive model launch across its entire product surface at once.",tags:["Google","Gemini 3","Multimodal","1M Context","Deep Think","Agents"],significance:"landmark",provider:"Google",providerColor:"#4285f4",url:"https://workspaceupdates.googleblog.com/2025/11/introducing-gemini-3-pro-for-gemini-app.html"},{id:"claude-opus-4-5",date:"Nov 2025",dateNum:202511,title:"Claude Opus 4.5 — First Model to Break 80% on SWE-bench",summary:"Anthropic released Claude Opus 4.5 on November 24, 2025, scoring 80.9% on SWE-bench Verified — the first AI model to cross the 80% threshold on the leading real-world coding benchmark, surpassing GPT-5.1 at 76.3% and Gemini 3 Pro at 76.2%. Pricing dropped by approximately 67% from previous Opus models to $5 per million input tokens and $25 per million output tokens. An 'endless chat' feature automatically compressed context at limits, enabling uninterrupted multi-hour agentic workflows.",tags:["Anthropic","Claude Opus 4.5","SWE-bench","Coding","Agents","Pricing"],significance:"landmark",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-opus-4-5"},{id:"gpt-5-2-codex",date:"Dec 2025",dateNum:202512,title:"OpenAI GPT-5.2-Codex — Agentic Coding Specialist Counters Gemini 3",summary:"OpenAI released GPT-5.2-Codex in December 2025 as a specialist coding model optimized for multi-step agentic software engineering tasks, directly responding to Gemini 3 Pro's strong coding performance. The model was positioned for autonomous repository-level coding, integration testing, and codebase exploration rather than single-file tasks. GPT-5.2-Codex debuted on the OpenAI Codex platform and via the Assistants API, targeting professional engineering teams running long-horizon automated workflows.",tags:["OpenAI","GPT-5.2","Codex","Coding","Agents","Agentic"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/introducing-gpt-5-2-codex/"},{id:"meta-manus",date:"Dec 2025",dateNum:202512,title:"Meta Acquires Manus AI for $2B+ — General-Purpose Agent Platform",summary:"Meta acquired Manus, a Singapore-based AI startup, for over $2 billion — the largest acquisition of an AI agent company to date. Manus had built a general-purpose AI agent capable of performing complex multi-step real-world tasks across web browsing, file management, coding, and data analysis without domain-specific customization. The acquisition positioned Meta to compete directly with OpenAI Operator and Anthropic Computer Use in the emerging market for autonomous agent products.",tags:["Meta","Manus","Agents","Acquisition","Automation"],significance:"major",provider:"Meta",providerColor:"#0866ff"},{id:"gemini-3-1-pro",date:"Feb 2026",dateNum:202602,title:"Gemini 3.1 Pro — Leads Every Published Reasoning Benchmark",summary:"Google released Gemini 3.1 Pro in February 2026, immediately reaching the top of all major published benchmarks including GPQA Diamond at 94.3% and ARC-AGI-2 at 77.1%. The model matched GPT-5.5's 1-million-token context window while offering more competitive API pricing, making it the preferred choice for cost-sensitive high-throughput workloads. Gemini 3.1 Flash-Lite launched simultaneously as Google's most cost-efficient model for latency-critical production deployments.",tags:["Google","Gemini 3.1 Pro","Reasoning","GPQA","ARC-AGI","Benchmark"],significance:"major",provider:"Google",providerColor:"#4285f4"},{id:"openai-122b-funding",date:"Mar 2026",dateNum:202603,dateDay:31,title:"OpenAI Closes $122B Round at $852B Valuation — Largest Private Raise Ever",summary:"OpenAI closed a $122 billion funding round on March 31, 2026 at an $852 billion post-money valuation — the largest private capital raise in history. Amazon committed $50 billion, SoftBank and Nvidia each contributed $30 billion, with Andreessen Horowitz and D.E. Shaw also participating. The round included $3 billion from individual investors via bank channels, and is expected to fund global AI infrastructure buildout and an anticipated IPO.",tags:["OpenAI","Funding","Valuation","SoftBank","Amazon","IPO"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/accelerating-the-next-phase-ai/"},{id:"claude-mythos-glasswing",date:"Apr 2026",dateNum:202604,title:"Claude Mythos and Project Glasswing — AI Discovers Thousands of Zero-Days",summary:"Anthropic announced Claude Mythos Preview, a frontier model sitting a full capability tier above Opus 4.7 and not available to the public, alongside Project Glasswing — an initiative to use Mythos to secure critical software infrastructure. Using Mythos, Anthropic autonomously identified thousands of zero-day vulnerabilities across every major operating system and web browser, including a 17-year-old remote code execution vulnerability in FreeBSD that allows complete server takeover. Launch partners include AWS, Apple, Cisco, CrowdStrike, Google, JPMorganChase, Microsoft, and NVIDIA, with $100 million in model credits committed.",tags:["Anthropic","Claude Mythos","Project Glasswing","Security","Zero-Day","Cybersecurity"],significance:"landmark",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/glasswing"},{id:"gemini-3-1-ultra",date:"Apr 2026",dateNum:202604,title:"Gemini 3.1 Ultra — 2M-Token Context Window, Full Native Multimodal",summary:"Google released Gemini 3.1 Ultra in April 2026 with the largest context window of any publicly available model at 2 million tokens — double the 1M-token limit of Gemini 3.1 Pro. The model reasons natively across text, image, audio, and video in a single pass without separate pipelines, enabling tasks like auditing a full year of all-hands recordings alongside a complete legal discovery set in one prompt. Gemini 3.1 Ultra surpassed GPT-5.5 on the MMLU-Pro and GPQA Diamond benchmarks, making it Google's most capable model available via the Vertex AI API at launch.",tags:["Google","Gemini 3.1 Ultra","2M Context","Multimodal","Benchmark","Vertex AI"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://medium.com/@WinTK-Bangladesh/gemini-3-1-ultra-is-here-2-million-token-context-full-multimodal-zero-compromise-ca3f2a8d1254"},{id:"claude-opus-4-7",date:"Apr 2026",dateNum:202604,title:"Claude Opus 4.7 — Anthropic's 2026 Flagship With Enhanced Vision and Coding",summary:"Anthropic released Claude Opus 4.7 on April 16, 2026, delivering a 10.9-point improvement on SWE-bench Pro to 64.3%, a threefold increase in visual resolution to 3.75 megapixels per image, enhanced file-system memory for persistent agentic tasks, and a new 'xhigh' reasoning effort level above the previous maximum. Pricing remained unchanged at $5 per million input and $25 per million output tokens despite the capability improvements. Opus 4.7 led software engineering and tool orchestration benchmarks against all competing models at launch.",tags:["Anthropic","Claude Opus 4.7","SWE-bench","Vision","Coding","Reasoning"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-opus-4-7"},{id:"gpt-5-5",date:"Apr 2026",dateNum:202604,title:"GPT-5.5 — OpenAI's 1M-Context Default Model With Agentic Workflows",summary:"OpenAI released GPT-5.5 on April 24, 2026, matching Gemini 3.1 Pro's 1-million-token context window for the first time while improving token efficiency at equivalent latency versus GPT-5.4. Greg Brockman described GPT-5.5 as 'a new class of intelligence' for its ability to decompose ambiguous problems and determine next steps without explicit instruction. GPT-5.5 Instant subsequently became the default model for all ChatGPT users in May 2026, replacing GPT-4o as the standard-tier model.",tags:["OpenAI","GPT-5.5","1M Context","Agentic","ChatGPT","Default Model"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://techcrunch.com/2026/05/05/openai-releases-gpt-5-5-instant-a-new-default-model-for-chatgpt/"},{id:"anthropic-30b-revenue",date:"May 2026",dateNum:202605,dateDay:8,title:"Anthropic Hits $30B Revenue Run-Rate — $950B Valuation Talks",summary:"Anthropic's annualized revenue surpassed $30 billion in May 2026 — more than triple its $9 billion run-rate at end of 2025 — driven by explosive enterprise adoption of Claude Opus 4.7 and Claude Code. The company entered talks to raise $30–50 billion at a valuation approaching $950 billion, which would make it one of the most valuable private companies in history. Anthropic simultaneously expanded its compute partnership with Google and Broadcom to support the infrastructure demands of serving its rapidly growing customer base.",tags:["Anthropic","Revenue","Valuation","Enterprise","Growth"],significance:"notable",provider:"Anthropic",providerColor:"#d97706"},{id:"xai-dissolved-anthropic-compute",date:"May 2026",dateNum:202605,dateDay:6,title:"xAI Dissolved — SpaceX Hands Colossus 1 Compute to Anthropic",summary:"Elon Musk announced on May 6, 2026 that xAI would be dissolved as an independent company and rebranded SpaceXAI, citing Anthropic's rapid growth and safety focus as factors in his change of view. Anthropic simultaneously signed a compute agreement with SpaceX giving it exclusive access to the Colossus 1 facility in Memphis — over 220,000 NVIDIA H100/H200/GB200 GPUs and 300 megawatts of capacity — driven by an 80-fold revenue surge in a single quarter that overwhelmed Anthropic's existing infrastructure. Anthropic also expressed interest in extending the partnership to gigawatt-scale orbital compute with SpaceX.",tags:["Anthropic","xAI","SpaceX","Compute","Colossus","Elon Musk","Infrastructure"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://x.ai/news/anthropic-compute-partnership"},{id:"mistral-medium-3-5",date:"May 2026",dateNum:202605,dateDay:1,title:"Mistral Medium 3.5 — 128B Open-Weight Model With 77.6% SWE-bench",summary:"Mistral AI released Medium 3.5, a 128-billion-parameter dense model with a 256,000-token context window, scoring 77.6% on SWE-bench Verified and unifying instruction-following, reasoning, coding, and vision in a single set of weights. The model was released with open weights under a modified MIT license and priced at $1.50/$7.50 per million input/output tokens via API. Mistral simultaneously launched Work Mode in Le Chat — an agentic interface powered by Medium 3.5 that executes multi-step workflows across connected tools in parallel.",tags:["Mistral AI","Medium 3.5","128B","Open Weights","SWE-bench","Agents"],significance:"major",provider:"Mistral AI",providerColor:"#ff7000",url:"https://mistral.ai/news/vibe-remote-agents-mistral-medium-3-5"},{id:"microsoft-agent-365-ga",date:"May 2026",dateNum:202605,dateDay:1,title:"Microsoft Agent 365 Generally Available — Enterprise AI Agent Governance",summary:"Microsoft made Agent 365 generally available on May 1, 2026, introducing enterprise-grade visibility, governance, and security controls for AI agent fleets at $15 per user per month. The platform extends Microsoft Entra network controls to Copilot Studio agents and locally-running agents, enabling IT teams to identify unsanctioned AI usage, restrict connections to approved destinations, and block prompt-injection attacks. Agent 365 is bundled into the new Microsoft 365 E7 tier alongside Copilot and the full Microsoft 365 E5 suite.",tags:["Microsoft","Agent 365","Enterprise","Governance","Security","Copilot"],significance:"major",provider:"Microsoft",providerColor:"#0078d4",url:"https://www.microsoft.com/en-us/security/blog/2026/05/01/microsoft-agent-365-now-generally-available-expands-capabilities-and-integrations/"},{id:"pentagon-ai-classified-deals",date:"May 2026",dateNum:202605,dateDay:1,title:"Pentagon Clears 8 AI Companies for Classified Military Networks",summary:"The US Department of Defense announced agreements with eight companies — OpenAI, Google, Microsoft, Nvidia, Amazon, SpaceX, Oracle, and Reflection — to deploy AI on its Impact Level 6 and Level 7 classified networks on May 1, 2026. The deals target warfighter decision-making and data synthesis, with all companies pledging not to use the technology for autonomous weapons or mass surveillance. Anthropic was excluded after the Trump administration objected to the company's insistence on safety guardrails governing AI use in warfare.",tags:["OpenAI","Google","Microsoft","Pentagon","Defense","Policy","Regulation"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://www.washingtonpost.com/technology/2026/05/01/pentagon-ai-deals-microsoft-amazon-google-classified-military/"},{id:"caisi-frontier-labs",date:"May 2026",dateNum:202605,dateDay:5,title:"All Five Frontier AI Labs Now Under US Government Pre-Deployment Review",summary:"The US Department of Commerce's Center for AI Standards and Innovation finalized pre-deployment evaluation agreements with Google DeepMind, Microsoft, and xAI on May 5, 2026, joining OpenAI and Anthropic in a program that has now completed more than 40 frontier model assessments. Under the agreements, every major model from these labs must undergo government safety and security evaluation before public release. The expansion marks the clearest signal yet that pre-deployment government review is becoming a baseline expectation for frontier AI development in the United States.",tags:["Regulation","CAISI","Google","Microsoft","xAI","Safety","Policy"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://www.cnbc.com/2026/05/05/ai-oversight-trump-google-microsoft-xai.html"},{id:"claude-small-business",date:"May 2026",dateNum:202605,dateDay:13,title:"Claude for Small Business — 15 Agentic Workflows Across Core Business Tools",summary:"Anthropic launched Claude for Small Business on May 13, 2026, shipping 15 ready-to-run agentic workflows spanning finance, operations, sales, marketing, HR, and customer service, with native connectors for QuickBooks, PayPal, HubSpot, Canva, Docusign, Google Workspace, Microsoft 365, and Slack. The workflows automate recurring tasks including payroll planning, month-end close, invoice chasing, lead triage, contract review, and cash-flow monitoring. Existing Claude Team and Enterprise subscribers get access at no additional cost, with the agent reusing the user's existing permissions on each connected application.",tags:["Anthropic","Claude","Agents","Small Business","QuickBooks","Automation"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/claude-for-small-business"},{id:"anthropic-gates-foundation",date:"May 2026",dateNum:202605,dateDay:14,title:"Anthropic and Gates Foundation Launch $200M Global Health and Education AI Initiative",summary:"Anthropic and the Bill & Melinda Gates Foundation announced a $200 million, four-year partnership on May 14, 2026 to deploy Claude in global health, education, and agriculture programs serving low- and middle-income countries. The deal includes grant funding, Claude usage credits, and technical support, targeting disease response acceleration, evidence-based K-12 tutoring, and smallholder farming assistance in sub-Saharan Africa and India. The partnership is four times the size of OpenAI's $50 million Gates deal announced in January 2026.",tags:["Anthropic","Claude","Gates Foundation","Global Health","Education","Partnership"],significance:"notable",provider:"Anthropic",providerColor:"#d97706",url:"https://www.anthropic.com/news/gates-foundation-partnership"},{id:"gemini-3-5-flash-io2026",date:"May 2026",dateNum:202605,dateDay:19,title:"Gemini 3.5 Flash — Google I/O 2026 Flagship Beats 3.1 Pro on Coding and Agents",summary:"Google launched Gemini 3.5 Flash at Google I/O on May 19, 2026 as the first model in the Gemini 3.5 family, immediately becoming the default model in the Gemini app and AI Mode in Google Search. The model outperforms Gemini 3.1 Pro on coding and agentic benchmarks — Terminal-Bench 2.1 at 76.2%, MCP Atlas at 83.6%, CharXiv Reasoning at 84.2% — while running 4\xd7 faster in output tokens per second. API pricing is $1.50 per million input tokens and $9.00 per million output tokens, approximately 40% cheaper than Gemini 3.1 Pro. Gemini 3.5 Pro was previewed as coming in June 2026.",tags:["Google","Gemini 3.5","Google I/O","Coding","Agents","Benchmark"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://www.digit.in/features/general/google-io-2026-gemini-35-to-ai-smart-glasses-everything-that-was-announced.html"},{id:"google-search-ai-mode-overhaul",date:"May 2026",dateNum:202605,dateDay:19,title:"Google Search's Biggest Redesign in 25 Years — AI Agents and Generative UI",summary:"Google unveiled a complete AI overhaul of Search at Google I/O on May 19, 2026, described as the biggest change to the search box in over 25 years. The new intelligent search box accepts text, images, files, videos, and Chrome tabs as inputs; agentic 'information agents' launching in summer 2026 will monitor the web continuously and alert users to changes. Generative UI, powered by Gemini 3.5 Flash, allows Search to dynamically produce custom interfaces, simulations, graphs, and mini-apps in response to queries. AI Mode already surpassed one billion monthly users with query volumes more than doubling every quarter since launch.",tags:["Google","Search","AI Mode","Agents","Generative UI","Google I/O","Gemini"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/products-and-platforms/products/search/search-io-2026/"},{id:"gemini-spark-agent-io2026",date:"May 2026",dateNum:202605,dateDay:19,title:"Gemini Spark — Google's 24/7 AI Agent Launches at Google I/O 2026",summary:"Google announced Gemini Spark at Google I/O on May 19, 2026 — a cloud-based AI agent that runs continuously in the background, reasoning across connected apps and taking actions on behalf of users. Spark integrates with Gmail, Docs, Uber, OpenTable, Lyft, Zillow, and dozens of third-party services, enabling autonomous multi-step workflows such as booking restaurants, tracking packages, and organizing calendar events. Beta access is included with the new Google AI Ultra subscription at $100 per month, rolling out first to trusted testers.",tags:["Google","Gemini Spark","Google I/O","Agents","Automation","AI Ultra"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://www.cnbc.com/2026/05/19/google-ai-ultra-gemini-spark-omni.html"},{id:"gemini-omni-io2026",date:"May 2026",dateNum:202605,dateDay:19,title:"Gemini Omni — Google's Unified Video-Image Generation Model Unveiled",summary:"Google DeepMind CEO Demis Hassabis unveiled Gemini Omni at Google I/O 2026, a multimodal model that unifies text, image, and video generation in a single set of weights — the first top-tier AI system to do so. Omni supports conversational video editing via voice commands, allowing users to transform uploaded footage by adjusting characters, backgrounds, and framing in real time. The initial release, Gemini Omni Flash, is grounded in real-world knowledge via Google Search and is planned for launch in summer 2026.",tags:["Google","Gemini Omni","Google I/O","Video Generation","Multimodal","DeepMind"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://www.businesstoday.in/technology/artificial-intelligence/story/google-io-2026-google-unveils-gemini-omni-ai-video-editing-model-532350-2026-05-19"},{id:"google-samsung-xr-glasses",date:"May 2026",dateNum:202605,dateDay:19,title:"Google and Samsung Unveil Gemini-Powered Android XR Smart Glasses",summary:"Google and Samsung revealed the first Android XR smart glasses at Google I/O 2026, with eyewear frames designed by Gentle Monster and Warby Parker for fall 2026 availability. The two-tier lineup includes audio-only glasses with cameras and microphones for all-day wear, and an optional in-lens display variant for private contextual information. Powered by Gemini, the glasses support live translation, navigation, calls, messaging, and real-time visual assistance, activated by voice or a tap on the frame.",tags:["Google","Samsung","Android XR","Smart Glasses","Wearables","Gemini","Google I/O"],significance:"notable",provider:"Google",providerColor:"#4285f4",url:"https://www.techradar.com/news/live/google-io-2026-live"},{id:"google-gemma-4",date:"Apr 2026",dateNum:202604,dateDay:2,title:"Gemma 4 — Google's Most Capable Open-Source Model Family",summary:"Google released Gemma 4 on April 2, 2026 under Apache 2.0, in four sizes (2B to 31B parameters) with 256K context windows, native vision and audio processing, and support for 140+ languages. The 31B dense flagship targets advanced reasoning, multi-step planning, agentic workflows, and offline code generation — available on Hugging Face, Kaggle, and Google AI Studio.",tags:["Google","Gemma","Open Source","Multimodal","Reasoning"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://blog.google/innovation-and-ai/technology/developers-tools/gemma-4/"},{id:"cohere-aleph-alpha-merger",date:"Apr 2026",dateNum:202604,dateDay:24,title:"Cohere Merges With Aleph Alpha — $20B Transatlantic AI Company Formed",summary:"Canadian AI firm Cohere and Germany's Aleph Alpha announced a merger on April 24, 2026, forming a transatlantic enterprise AI company valued at roughly $20 billion. The deal, anchored by a €500 million commitment from Schwarz Group (Lidl and Kaufland's parent), received backing from both the Canadian and German governments. Cohere CEO Aidan Gomez will lead the combined company, which will operate under the Cohere name and compete directly with US frontier labs for European and sovereign AI contracts.",tags:["Cohere","Aleph Alpha","Merger","Europe","Enterprise AI","Sovereign AI"],significance:"notable",provider:"Cohere",providerColor:"#39c5cf",url:"https://techcrunch.com/2026/04/25/why-cohere-is-merging-with-aleph-alpha/"},{id:"deepseek-v4",date:"Apr 2026",dateNum:202604,dateDay:24,title:"DeepSeek V4 — 1.6T-Parameter MoE, 80.6% SWE-bench Verified",summary:"DeepSeek released V4-Pro and V4-Flash on April 24, 2026 under MIT license. V4-Pro packs 1.6T total parameters with 49B active via mixture-of-experts, a 1M-token context window, and scored 80.6% on SWE-bench Verified — matching frontier closed-source models. Weights are on Hugging Face; V4-Flash (284B total, 13B active) targets cost-efficient inference.",tags:["DeepSeek","V4","Open Source","MoE","Coding","SWE-bench"],significance:"major",provider:"DeepSeek",providerColor:"#1a73e8",url:"https://huggingface.co/deepseek-ai/DeepSeek-V4-Pro"},{id:"anthropic-dreaming-agents",date:"May 2026",dateNum:202605,dateDay:6,title:"Anthropic Dreaming — Claude Agents Now Self-Improve Between Sessions",summary:"Anthropic launched Dreaming on May 6, 2026, a scheduled maintenance layer that reviews an agent's past sessions, extracts patterns across them, and curates memory stores so agents improve over time without modifying model weights. Supported on Claude Opus 4.7 and Sonnet 4.6, Dreaming feeds up to 100 past sessions into a single 'dream' and surfaces recurring mistakes, convergent workflows, and team-wide preferences. Early adopter Harvey (legal AI) reported a 6\xd7 increase in task completion rates after implementing the feature; access is currently gated behind a request form.",tags:["Anthropic","Claude","Dreaming","Agents","Memory","Self-Improvement"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://venturebeat.com/technology/anthropic-introduces-dreaming-a-system-that-lets-ai-agents-learn-from-their-own-mistakes"},{id:"anthropic-managed-agents-sandboxes-mcp-tunnels",date:"May 2026",dateNum:202605,dateDay:19,title:"Anthropic Launches Self-Hosted Sandboxes and Encrypted MCP Tunnels for Claude Agents",summary:"Announced at Code with Claude London (May 19–20, 2026), Anthropic released self-hosted sandboxes in public beta and MCP tunnels in research preview for Claude Managed Agents. Self-hosted sandboxes let enterprises run agent tool execution on their own infrastructure — or via Cloudflare, Daytona, Modal, or Vercel — while Anthropic retains orchestration. MCP tunnels provide end-to-end encrypted access to private MCP servers with no inbound firewall rules required, enabling agents to reach internal databases and APIs without public exposure.",tags:["Anthropic","Claude","Managed Agents","MCP","Agent Infrastructure","Security"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://claude.com/blog/claude-managed-agents-updates"},{id:"recursive-superintelligence-650m-launch",date:"May 2026",dateNum:202605,dateDay:13,title:"Recursive Superintelligence Exits Stealth with $650M at $4.65B Valuation",summary:"UK-based startup Recursive Superintelligence exited stealth on May 13, 2026 with $650 million raised at a $4.65 billion valuation, backed by GV (Alphabet's VC arm), Greycroft, Nvidia, and AMD. Co-founded by ex-Salesforce chief scientist Richard Socher and UCL/DeepMind professor Tim Rockt\xe4schel, the 30-person team is building AI systems that autonomously improve themselves in recursive loops — starting with AI-driven AI research. A Level 1 autonomous training system is targeted for public launch in mid-2026.",tags:["Recursive Superintelligence","Funding","Self-Improving AI","Stealth Launch","UK AI"],significance:"major",provider:"Recursive Superintelligence",providerColor:"#6d28d9",url:"https://tech.eu/2026/05/13/recursive-superintelligence-emerges-from-stealth-with-650m-raise/"},{id:"eu-ai-act-omnibus-simplification-may-2026",date:"May 2026",dateNum:202605,dateDay:7,title:"EU Parliament and Council Agree AI Act Omnibus Simplification",summary:"The European Parliament and Council reached a provisional agreement on May 7, 2026 on the Digital Omnibus package, delaying high-risk AI compliance deadlines — standalone systems to December 2027, product-embedded systems to August 2028 — and reducing administrative burdens for SMEs and mid-caps. New prohibitions on non-consensual intimate AI imagery and CSAM generation take effect December 2026. The deal also broadens permissions for sensitive data use in bias mitigation; formal adoption is expected before the original August 2, 2026 deadline.",tags:["EU","Regulation","AI Act","Policy","Compliance","Digital Omnibus"],significance:"major",provider:"European Union",providerColor:"#003399",url:"https://www.consilium.europa.eu/en/press/press-releases/2026/05/07/artificial-intelligence-council-and-parliament-agree-to-simplify-and-streamline-rules/"},{id:"musk-openai-lawsuit-verdict",date:"May 2026",dateNum:202605,dateDay:18,title:"Jury Dismisses All of Musk's Claims Against OpenAI in Under Two Hours",summary:"A California jury deliberated less than two hours on May 18, 2026 before rejecting all claims in Elon Musk's lawsuit against OpenAI, Sam Altman, and Greg Brockman. The jury found Musk was aware of OpenAI's shift to a for-profit structure as early as 2021, barring his claims under the statute of limitations. Musk had sought up to $134 billion in damages and Altman's removal; he vowed to appeal, calling the verdict a 'technicality.'",tags:["OpenAI","Elon Musk","Legal","xAI","Sam Altman"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://www.npr.org/2026/05/18/nx-s1-5822366/musk-altman-openai-jury-verdict-claims-dismissed"},{id:"cursor-composer-25",date:"May 2026",dateNum:202605,dateDay:18,title:"Cursor Releases Composer 2.5 — Opus 4.7-Level Coding at a Fraction of the Price",summary:"Cursor launched Composer 2.5 on May 18, 2026, achieving 79.8% on SWE-Bench Multilingual and Terminal-Bench scores matching Claude Opus 4.7, while pricing stays at $0.50/$2.50 per million input/output tokens — a fraction of frontier model costs. The model was trained on 25\xd7 more synthetic tasks with tougher reinforcement-learning environments, enabling longer multi-file editing sessions and more reliable terminal operations. Cursor's valuation stands at $29 billion following its most recent funding round.",tags:["Cursor","Coding","SWE-Bench","IDE","Developer Tools"],significance:"notable",provider:"Cursor",providerColor:"#8b5cf6",url:"https://winbuzzer.com/2026/05/18/cursor-releases-composer-25-saying-its-better-at-s-xcxwbn/"},{id:"pope-leo-magnifica-humanitas-encyclical",date:"May 2026",dateNum:202605,dateDay:18,title:"Pope Leo XIV Announces 'Magnifica Humanitas' — First Papal Encyclical on AI, Co-Presented with Anthropic Co-Founder",summary:"The Vatican announced on May 18, 2026 that Pope Leo XIV will publish 'Magnifica Humanitas,' the first papal encyclical on artificial intelligence, on May 25 — signed May 15, exactly 135 years after Leo XIII's Rerum Novarum addressed the Industrial Revolution. The document will be co-presented at the Vatican's Synod Hall alongside Christopher Olah, co-founder of Anthropic, alongside cardinals and theologians. The encyclical addresses preserving human dignity in the age of AI and was developed as AI companies, including Anthropic, have resisted pressure to remove safety guardrails for autonomous weapons.",tags:["Anthropic","AI Ethics","Vatican","Policy","Christopher Olah","Religion"],significance:"notable",provider:"Anthropic",providerColor:"#d97706",url:"https://www.vaticannews.va/en/pope/news/2026-05/pope-leo-xiv-first-encyclical-magnifica-humanitas.html"},{id:"openai-chatgpt-ads-manager",date:"May 2026",dateNum:202605,dateDay:5,title:"OpenAI Launches Self-Serve ChatGPT Ads Manager — No Minimum Spend",summary:"OpenAI opened ChatGPT Ads Manager to U.S. businesses on May 5, 2026, eliminating the previous $50,000 minimum spend requirement and introducing cost-per-click bidding with real-time campaign management. The platform targets $2.5 billion in ad revenue for 2026 and $100 billion by 2030; ad agency partners include Dentsu, Omnicom, Publicis, and WPP, with ad-tech integrations through Adobe, Criteo, Kargo, and StackAdapt. OpenAI confirmed no user conversations or personal data are shared with advertisers.",tags:["OpenAI","ChatGPT","Advertising","Monetization","Business"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/new-ways-to-buy-chatgpt-ads/"},{id:"claude-microsoft-365-ga",date:"May 2026",dateNum:202605,dateDay:7,title:"Claude for Microsoft 365 Reaches GA — Excel, Word, PowerPoint, and Outlook Beta",summary:"Anthropic moved Claude add-ins for Excel, Word, and PowerPoint to general availability on May 7, 2026 across all paid Claude plans on Mac and Windows, and simultaneously launched Claude for Outlook in public beta. The standout feature is cross-app context: a single conversation thread persists across all four Microsoft 365 applications, so Claude remembers the financial model discussed in Excel when the user opens the related PowerPoint deck. The integration reaches more than 400 million Microsoft 365 commercial users and is deployable via Microsoft Admin Center.",tags:["Anthropic","Claude","Microsoft 365","Excel","Outlook","Enterprise"],significance:"major",provider:"Anthropic",providerColor:"#d97706",url:"https://claude.com/claude-for-microsoft-365"},{id:"amazon-alexa-plus-podcasts",date:"May 2026",dateNum:202605,dateDay:18,title:"Amazon Alexa+ Generates On-Demand AI Podcasts from Any Topic",summary:"Amazon launched Alexa Podcasts on May 18, 2026, letting Alexa+ subscribers request a podcast on any subject and receive a fully structured audio episode narrated by two AI co-hosts. The feature taps licensing agreements with over 200 news organisations — including AP, Reuters, the Washington Post, Forbes, and Cond\xe9 Nast — plus 200+ local U.S. newspapers. Alexa+ is included with Amazon Prime at no extra cost; non-Prime users pay $19.99/month.",tags:["Amazon","Alexa","Podcasts","AI Audio","Content Generation"],significance:"notable",provider:"Amazon",providerColor:"#FF9900",url:"https://techcrunch.com/2026/05/18/amazons-new-alexa-powered-feature-can-generate-podcast-episodes/"},{id:"google-ai-ultra-100-900m-users",date:"May 2026",dateNum:202605,dateDay:19,title:"Google Cuts AI Ultra to $100/Month as Gemini Hits 900 Million Monthly Users",summary:"At Google I/O 2026, Google slashed the price of its Google AI Ultra subscription from $250 to $100 per month, bundling 5\xd7 higher Gemini app usage limits, 20 TB of cloud storage, and YouTube Premium, with beta access to Gemini Spark rolling out the following week for U.S. subscribers. The Gemini app has crossed 900 million monthly active users — up from 400 million a year earlier — doubling in a year. DeepMind CEO Demis Hassabis stated at the keynote that Artificial General Intelligence is 'just a few years away.'",tags:["Google","Gemini","Google I/O","Pricing","AGI","DeepMind"],significance:"major",provider:"Google",providerColor:"#4285f4",url:"https://www.techtimes.com/articles/316853/20260519/google-cuts-ai-ultra-100-launches-gemini-spark-agent-android-xr-glasses-i-o-2026.htm"},{id:"apple-ios27-third-party-ai-models",date:"May 2026",dateNum:202605,dateDay:5,title:"Apple iOS 27 to Let Users Choose Between Claude, Gemini, and ChatGPT for Siri",summary:"Bloomberg reported on May 5, 2026 that Apple is preparing iOS 27 to support third-party AI models — including Google Gemini and Anthropic Claude — as alternatives to OpenAI across Siri, Writing Tools, and Image Playground. Apple is already in closed-door testing with Google and Anthropic and internally refers to the feature as 'Extensions', configurable from the Settings app. The shift is expected to be previewed at WWDC 2026 and ship with iOS 27 in fall 2026, opening Apple Intelligence to the full competitive frontier.",tags:["Apple","iOS 27","Apple Intelligence","Siri","Anthropic","Google","OpenAI"],significance:"major",provider:"Apple",providerColor:"#555555",url:"https://techcrunch.com/2026/05/05/apple-plans-to-make-ios-27-a-choose-your-own-adventure-of-ai-models/"},{id:"openai-chatgpt-personal-finance",date:"May 2026",dateNum:202605,dateDay:15,title:"OpenAI Launches ChatGPT Personal Finance — Connect Bank Accounts via Plaid",summary:"OpenAI launched personal finance tools in ChatGPT on May 15, 2026 for Pro subscribers in the U.S., letting users connect accounts from 12,000+ financial institutions — including Chase, Fidelity, Schwab, Robinhood, and American Express — via Plaid. Once linked, ChatGPT surfaces a dashboard of portfolio performance, spending patterns, subscriptions, and upcoming payments, and can answer open-ended financial planning questions. Account numbers cannot be seen and no account changes can be made; OpenAI plans to expand to Plus users after refining the feature.",tags:["OpenAI","ChatGPT","Personal Finance","Plaid","Banking","FinTech"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://techcrunch.com/2026/05/15/openai-launches-chatgpt-for-personal-finance-will-let-you-connect-bank-accounts/"},{id:"openai-google-synthid-c2pa-provenance",date:"May 2026",dateNum:202605,dateDay:20,title:"OpenAI and Google Partner on SynthID Watermarks and C2PA to Verify AI-Generated Images",summary:"OpenAI joined the C2PA Steering Committee on May 20, 2026 and partnered with Google DeepMind to embed SynthID invisible watermarks into all images generated through ChatGPT, Codex, and the OpenAI API. SynthID watermarks survive transformations like screenshots and format changes that strip standard metadata. OpenAI also launched a public verification tool at openai.com/verify where anyone can upload an image to check whether it originated from ChatGPT or the OpenAI API, with plans for cross-platform verification in coming months.",tags:["OpenAI","Google","SynthID","C2PA","AI Safety","Content Provenance","Watermarking"],significance:"major",provider:"OpenAI",providerColor:"#10a37f",url:"https://openai.com/index/advancing-content-provenance/"}],t=n;Array.from(new Set(n.flatMap(e=>e.tags))).sort()}}]);